import { useEffect, useState } from "react";

import "./styles/GlobalSearch.css";

export default function SearchResultsPage() {
    const [results, setResults] = useState(null);
    const [loading, setLoading] = useState(true);

    const params = new URLSearchParams(window.location.hash.split("?")[1]);
    const q = params.get("q") || "";

    useEffect(() => {
        setLoading(true);

        fetch(`/api/search?q=${encodeURIComponent(q)}`)
            .then(r => r.json())
            .then(data => {
                setResults(data);
                setLoading(false);
            });
    }, [q]);

    if (loading) {
        return <div style={{ padding: 24 }}>Searching…</div>;
    }

    return (
        <div style={{ maxWidth: 900, margin: "0 auto", padding: 24 }}>
            <h2 style={{ marginBottom: 24 }}>
                Search results for “{q}”
            </h2>

            <Section title="Events" items={results.events} />
            <Section title="Clubs" items={results.clubs} />
            <Section title="Threads" items={results.threads} />
            <Section title="Posts" items={results.posts} />
        </div>
    );
}

function Section({ title, items }) {
    if (!items || items.length === 0) return null;

    return (
        <div style={{ marginBottom: 32 }}>
            <h3 style={{ marginBottom: 12 }}>{title}</h3>

            {items.map(item => (
                <a
                    key={item.id}
                    href={item.url}
                    style={{
                        display: "block",
                        padding: "12px 16px",
                        borderBottom: "1px solid #2a2a2a",
                        textDecoration: "none",
                        color: "white"
                    }}
                >
                    <div style={{ fontWeight: 600 }}>
                        {item.title}
                    </div>

                    {item.subtitle && (
                        <div style={{ fontSize: 12, color: "#9aa0a6" }}>
                            {item.subtitle}
                        </div>
                    )}
                </a>
            ))}
        </div>
    );
}
